class User {
    field Str $name;
    field Int $age;
    field Optional[Email] $email;

    method new(Str $name, Int $age) -> User {
        return bless {
            name => $name,
            age => $age
        }, __PACKAGE__;
    }

    method get_name() -> Str {
        return $name;
    }
}
